import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.BPmc_f4o.js";const g=JSON.parse('{"title":"IP Filtering (Per-Application)","description":"","frontmatter":{},"headers":[],"relativePath":"ipsfilter/ipsfilter.md","filePath":"ipsfilter/ipsfilter.md"}'),r={name:"ipsfilter/ipsfilter.md"};function n(l,e,s,p,d,c){return a(),i("div",null,[...e[0]||(e[0]=[o('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="ip-filtering-per-application" tabindex="-1">IP Filtering (Per-Application) <a class="header-anchor" href="#ip-filtering-per-application" aria-label="Permalink to &quot;IP Filtering (Per-Application)&quot;">​</a></h1><p>Per-application IP Filtering is a Pro feature that adds application-scoped blocking on top of the <a href="/global-ip-filtering/global-ip-filtering.html">Global IP Filtering</a> layer. Because applications themselves are a Pro concept, this module is only available with a Pro licence.</p><table tabindex="0"><thead><tr><th>Layer</th><th>Scope</th><th>Tier</th><th>Doc</th></tr></thead><tbody><tr><td><strong>Global IP Filtering</strong></td><td>Shared across all applications — runs before application resolution</td><td>Free + Pro</td><td><a href="/global-ip-filtering/global-ip-filtering.html">→ Global IP Filtering</a></td></tr><tr><td><strong>Per-Application IP Filtering</strong></td><td>Additional blocks scoped to one application — runs after application resolution</td><td><strong>Pro only</strong></td><td>This page</td></tr></tbody></table><p>Use Global IP Filtering for shared threats such as known bots, scrapers, and unwanted geographies. Use per-application IP Filtering for rules that only apply to one specific application. An IP that passes the global check can still be blocked here for a specific application.</p><hr><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="cidr-ranges" tabindex="-1">CIDR Ranges <a class="header-anchor" href="#cidr-ranges" aria-label="Permalink to &quot;CIDR Ranges&quot;">​</a></h3><p>Define IP ranges using CIDR notation (e.g. <code>192.168.1.0/24</code>). Supports both IPv4 and IPv6.</p><h3 id="country-blocking" tabindex="-1">Country Blocking <a class="header-anchor" href="#country-blocking" aria-label="Permalink to &quot;Country Blocking&quot;">​</a></h3><p>Block requests by country using GeoIP data, scoped to this application. Country rules apply on top of individual IP rules.</p><h3 id="retention-time" tabindex="-1">Retention Time <a class="header-anchor" href="#retention-time" aria-label="Permalink to &quot;Retention Time&quot;">​</a></h3><p>Set an optional retention period. Entries are automatically removed when the retention time elapses.</p><hr><h2 id="ip-list-management" tabindex="-1">IP List Management <a class="header-anchor" href="#ip-list-management" aria-label="Permalink to &quot;IP List Management&quot;">​</a></h2><p>The IP list displays all active entries for this application (manual or auto-detected). For each entry:</p><ul><li><strong>Add</strong> an IP or CIDR range manually.</li><li><strong>Delete</strong> one or more entries individually or in bulk.</li></ul><p>Entries show the IP address, source (manual or auto-detected), detected country, and the optional retention expiry time.</p><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>How does per-application filtering relate to the global blocklist?</strong></p><p>Both layers run independently. The global blocklist is checked first. If the IP passes, the per-application list is checked next. An IP can be blocked at either level.</p><p><strong>Are IPv6 addresses supported?</strong></p><p>Yes. Both IPv4 and IPv6 are supported via CIDR notation.</p><p><strong>What happens to blocked IPs when an application is deleted?</strong></p><p>IP entries scoped to a deleted application are removed alongside it. Global entries are unaffected.</p>',26)])])}const u=t(r,[["render",n]]);export{g as __pageData,u as default};
